#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int M;
    cin >> M;

    vector<pair<int, int>> tasks(M);
    for (int i = 0; i < M; ++i) {
        cin >> tasks[i].first >> tasks[i].second; // deadline, time
    }

    // Sort by deadline
    sort(tasks.begin(), tasks.end());

    // Max-heap of task durations (we store negative to get max with default min-heap)
    // Actually we want to pop the largest duration when we exceed deadline.
    // We'll store durations as positive in a max-heap using greater<int>? Use std::priority_queue which is max-heap by default.
    priority_queue<int> durations;
    long long total_time = 0; // sum of durations of selected tasks

    for (auto &t : tasks) {
        int deadline = t.first;
        int duration = t.second;

        // Assume we take this task
        total_time += duration;
        durations.push(duration);

        // If we exceed the deadline, drop the longest task we've taken
        if (total_time > deadline) {
            total_time -= durations.top();
            durations.pop();
        }
    }

    cout << durations.size() << "\n";
    return 0;
}
